import { Component, OnInit } from '@angular/core';
import { SignupService } from 'src/app/registration/services/signup.service';
import { Router } from '@angular/router';
import { firstValueFrom, timeout, filter } from 'rxjs';
import { AuthService, User } from '@auth0/auth0-angular';

@Component({
  selector: 'app-redirect',
  templateUrl: './redirect.component.html',
  styleUrls: ['./redirect.component.scss']
})
export class RedirectComponent implements OnInit {
  constructor(private signupService: SignupService, private auth: AuthService, private router: Router) { }

  async ngOnInit() {
    await firstValueFrom(this.auth.isAuthenticated$.pipe(filter(authenticated => authenticated)));
    const user = await firstValueFrom(this.auth.user$);
    const riskAppetite = this.signupService.getItem('riskAppetite');
    const selectedTradingPairs = this.signupService.getItem('selectedTradingPairs');
    const accessToken = await firstValueFrom(this.auth.getAccessTokenSilently())

    if (riskAppetite === null || selectedTradingPairs === null) {
      await this.checkExistingUser();
    } else {
      if (user) {
        await this.createNewUser(user);
      }
    }
  }

  private async checkExistingUser() {
    try {
      const response = await firstValueFrom(this.signupService.getUser().pipe(timeout(5000)));
      this.router.navigate(['/trade/connect-wallet']);
    } catch (error) {
      this.auth.logout({ logoutParams: { returnTo: window.location.origin + '#/registration/risk-appetite' } });
    }
  }

  private async createNewUser(user: User) {
    try {
      const name = user?.given_name ? user?.given_name : 'No Name';
      const surname = user?.family_name ? user?.family_name : 'No Surname';
      const email = user?.email ? user?.email : 'No Email';
      const response = await firstValueFrom(this.signupService.createUser(name, surname, email).pipe(timeout(5000)));
      this.router.navigate(['/trade/connect-wallet']);
    } catch (error) {
      await this.checkExistingUser();
    }
  }
}
